<?php

use Imv\Gateway\Data\EImzo\EImzoTimestamp;
use Imv\Gateway\Data\EImzo\VerifyAttached;
use Imv\Gateway\Facades\Gateway;
use Imv\Gateway\Requests\EImzo\TimestampRequest;
use Imv\Gateway\Requests\EImzo\VerifyAttachedRequest;
use Saloon\Http\Faking\MockClient;
use Saloon\Http\Faking\MockResponse;
use Illuminate\Support\Facades\Config;

it('can get e-imzo timestamp and verify pkcs7b64', function () {
    $mockClient = new MockClient([
        TimestampRequest::class => MockResponse::make([
            'pkcs7b64' => '',
            'timestampedSignerList' => [
                [
                    'serialNumber' => '7866ba33',
                    'X500Name' => 'CN=SHUKUROV...',
                    'subjectName' => [
                        'ST' => 'Toshkent shahri',
                        'CN' => 'SHUKUROV ELBEK XABIBULLAYEVICH',
                    ],
                    'validFrom' => '2024-06-04 10:14:59',
                    'validTo' => '2026-06-04 10:15:01',
                ]
            ],
            'status' => 1,
            'message' => ''
        ], 200),
    ]);

    $connector = new \Imv\Gateway\Connectors\GatewayConnector();
    $connector->withMockClient($mockClient);

    $gateway = app(\Imv\Gateway\Gateway::class);
    
    $reflection = new ReflectionClass($gateway);
    $property = $reflection->getProperty('connector');
    $property->setAccessible(true);
    $property->setValue($gateway, $connector);

    $sign = '';
    $data = $gateway->getEImzoTimestamp($sign);

    expect($data)
        ->toBeInstanceOf(EImzoTimestamp::class)
        ->and($data->pkcs7b64)->toBeString()
        ->and($data->status)->toBe(1);
});

it('can verify attached', function () {
    $mockClient = new MockClient([
        VerifyAttachedRequest::class => MockResponse::make([
            'pkcs7Info' => [
                'signers' => [
                    [
                        'signerId' => [
                            'issuer' => 'CN=YANGI...',
                            'subjectSerialNumber' => '7866ba33'
                        ],
                        'signature' => '17cf095...',
                        'verified' => true,
                    ]
                ],
                'documentBase64' => 'MjIy',
            ],
            'status' => 1,
            'message' => ''
        ], 200),
    ]);

    $connector = new \Imv\Gateway\Connectors\GatewayConnector();
    $connector->withMockClient($mockClient);

    $gateway = app(\Imv\Gateway\Gateway::class);
    $reflection = new ReflectionClass($gateway);
    $property = $reflection->getProperty('connector');
    $property->setAccessible(true);
    $property->setValue($gateway, $connector);

    $pkcs7b64 = '<string>';
    $data = $gateway->verifyAttached($pkcs7b64);
    
    expect($data)
        ->toBeInstanceOf(VerifyAttached::class)
        ->and($data->pkcs7Info->documentBase64)->toBe('MjIy')
        ->and($data->pkcs7Info->signers[0]->signerId->subjectSerialNumber)->toBe('7866ba33')
        ->and($data->status)->toBe(1);
});
